import React from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Divider,
  Box,
  Spacer,
} from '@ggui-ai/design/primitives';

export interface ForecastItem {
  day: string;
  icon: string;
  high: number;
  low: number;
}

export interface Props {
  city: string;
  temperature: number;
  condition: string;
  humidity: number;
  windSpeed: number;
  unit?: string;
  forecast: ForecastItem[];
}

export default function WeatherCard({
  city,
  temperature,
  condition,
  humidity,
  windSpeed,
  unit = 'C',
  forecast,
}: Props) {
  return (
    <Card padding={24} shadow="md" radius="xl" border={true}>
      <Stack gap={24}>
        {/* Header Section */}
        <Stack direction="horizontal" justify="between" align="start">
          <Stack gap={2}>
            <Heading level={2} color="var(--ggui-color-onSurface, #18181b)">
              {city}
            </Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant, #52525b)">
              {new Date().toLocaleDateString('en-US', {
                weekday: 'long',
                month: 'long',
                day: 'numeric',
              })}
            </Text>
          </Stack>
          <Box
            paddingX={12}
            paddingY={6}
            background="var(--ggui-color-primary-50, #f0f9ff)"
            borderRadius="var(--ggui-shape-radius-full, 9999px)"
          >
            <Text
              variant="label"
              color="var(--ggui-color-primary-700, #0369a1)"
              weight="semibold"
            >
              {condition}
            </Text>
          </Box>
        </Stack>

        {/* Current Weather Main Display */}
        <Stack direction="horizontal" align="center" justify="center" gap={32}>
          <Text
            size="4xl"
            weight="bold"
            color="var(--ggui-color-onSurface, #18181b)"
            style={{ fontSize: 'var(--ggui-font-size-4xl, 64px)', lineHeight: 1 }}
          >
            {Math.round(temperature)}°{unit}
          </Text>
          <Text size="4xl" style={{ fontSize: '64px' }}>
            {getWeatherEmoji(condition)}
          </Text>
        </Stack>

        {/* Detail Stats */}
        <Box
          padding={16}
          background="var(--ggui-color-surfaceVariant, #f4f4f5)"
          borderRadius="var(--ggui-shape-radius-lg, 12px)"
        >
          <Stack direction="horizontal" justify="around" align="center">
            <Stack gap={4} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                HUMIDITY
              </Text>
              <Text variant="body" weight="semibold">
                {humidity}%
              </Text>
            </Stack>
            <Divider orientation="vertical" margin={0} color="var(--ggui-color-outline, #d4d4d8)" />
            <Stack gap={4} align="center">
              <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                WIND
              </Text>
              <Text variant="body" weight="semibold">
                {windSpeed} km/h
              </Text>
            </Stack>
          </Stack>
        </Box>

        <Divider margin={8} />

        {/* 5-Day Forecast Strip */}
        <Stack direction="horizontal" justify="between" align="center" wrap={false}>
          {forecast.slice(0, 5).map((item, index) => (
            <Stack key={`${item.day}-${index}`} gap={8} align="center" style={{ flex: 1 }}>
              <Text variant="label" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                {item.day}
              </Text>
              <Text size="xl">{item.icon}</Text>
              <Stack gap={2} align="center">
                <Text variant="bodySmall" weight="semibold">
                  {Math.round(item.high)}°
                </Text>
                <Text variant="caption" color="var(--ggui-color-onSurfaceVariant, #52525b)">
                  {Math.round(item.low)}°
                </Text>
              </Stack>
            </Stack>
          ))}
        </Stack>
      </Stack>
    </Card>
  );
}

/**
 * Helper to determine a fallback emoji if the forecast doesn't provide one,
 * or to match the main condition.
 */
function getWeatherEmoji(condition: string): string {
  const c = condition.toLowerCase();
  if (c.includes('sun') || c.includes('clear')) return '☀️';
  if (c.includes('cloud')) return '☁️';
  if (c.includes('rain') || c.includes('shower')) return '🌧️';
  if (c.includes('thunder') || c.includes('storm')) return '⛈️';
  if (c.includes('snow')) return '❄️';
  if (c.includes('mist') || c.includes('fog')) return '🌫️';
  return '⛅';
}

import React, { useState, useMemo } from 'react';
import {
  Stack,
  Box,
  Text,
  Heading,
  Card,
  Container,
  Spacer,
  Divider,
} from '@ggui-ai/design/primitives';
import { SearchField, Tag } from '@ggui-ai/design/components';

export interface Element {
  atomicNumber: number;
  symbol: string;
  name: string;
  atomicWeight: number;
  category: string;
  row: number;
  col: number;
}

export interface Props {
  elements: Element[];
}

/**
 * Maps element categories to design system color tokens
 */
const getCategoryColors = (category: string) => {
  const normalized = category.toLowerCase();
  if (normalized.includes('alkali-metal')) {
    return {
      bg: 'var(--ggui-color-error-50, #fef2f2)',
      border: 'var(--ggui-color-error-200, #fecaca)',
      text: 'var(--ggui-color-error-800, #991b1b)',
    };
  }
  if (normalized.includes('alkaline-earth')) {
    return {
      bg: 'var(--ggui-color-warning-50, #fffbeb)',
      border: 'var(--ggui-color-warning-200, #fde68a)',
      text: 'var(--ggui-color-warning-800, #92400e)',
    };
  }
  if (normalized.includes('transition-metal')) {
    return {
      bg: 'var(--ggui-color-primary-50, #f0f9ff)',
      border: 'var(--ggui-color-primary-200, #bae6fd)',
      text: 'var(--ggui-color-primary-800, #075985)',
    };
  }
  if (normalized.includes('post-transition')) {
    return {
      bg: 'var(--ggui-color-success-50, #f0fdf4)',
      border: 'var(--ggui-color-success-200, #bbf7d0)',
      text: 'var(--ggui-color-success-800, #166534)',
    };
  }
  if (normalized.includes('metalloid')) {
    return {
      bg: 'var(--ggui-color-info-50, #ecfeff)',
      border: 'var(--ggui-color-info-200, #a5f3fc)',
      text: 'var(--ggui-color-info-800, #155e75)',
    };
  }
  if (normalized.includes('noble-gas')) {
    return {
      bg: 'var(--ggui-color-container, #ede9fe)',
      border: 'var(--ggui-color-primary-200, #bae6fd)',
      text: 'var(--ggui-color-onContainer, #4c1d95)',
    };
  }
  if (normalized.includes('lanthanide') || normalized.includes('actinide')) {
    return {
      bg: 'var(--ggui-color-surfaceVariant, #f4f4f5)',
      border: 'var(--ggui-color-outline, #d4d4d8)',
      text: 'var(--ggui-color-onSurfaceVariant, #52525b)',
    };
  }
  if (normalized.includes('nonmetal') || normalized.includes('halogen')) {
    return {
      bg: 'var(--ggui-color-primary-100, #e0f2fe)',
      border: 'var(--ggui-color-primary-300, #7dd3fc)',
      text: 'var(--ggui-color-primary-900, #0c4a6e)',
    };
  }
  return {
    bg: 'var(--ggui-color-surface, #fafafa)',
    border: 'var(--ggui-color-outlineVariant, #e4e4e7)',
    text: 'var(--ggui-color-onSurface, #18181b)',
  };
};

export default function PeriodicTable(props: Props) {
  const { elements = [] } = props;
  const [searchTerm, setSearchTerm] = useState('');
  const [selectedElement, setSelectedElement] = useState<Element | null>(null);

  const filteredElements = useMemo(() => {
    if (!searchTerm) return elements;
    const lowerSearch = searchTerm.toLowerCase();
    return elements.filter(
      (el) =>
        el.name.toLowerCase().includes(lowerSearch) ||
        el.symbol.toLowerCase().includes(lowerSearch)
    );
  }, [elements, searchTerm]);

  // Unique categories for the legend
  const categories = useMemo(() => {
    const set = new Set(elements.map((el) => el.category));
    return Array.from(set).sort();
  }, [elements]);

  const handleElementClick = (element: Element) => {
    setSelectedElement(element);
  };

  const isHighlighted = (element: Element) => {
    if (!searchTerm) return true;
    const lowerSearch = searchTerm.toLowerCase();
    return (
      element.name.toLowerCase().includes(lowerSearch) ||
      element.symbol.toLowerCase().includes(lowerSearch)
    );
  };

  return (
    <Container maxWidth="xl" padding="var(--ggui-spacing-6)">
      <Stack gap="var(--ggui-spacing-8)">
        {/* Header and Search */}
        <Stack direction="horizontal" justify="between" align="end" wrap>
          <Stack gap="var(--ggui-spacing-1)">
            <Heading level={1}>Periodic Table of Elements</Heading>
            <Text variant="bodySmall" color="var(--ggui-color-onSurfaceVariant)">
              Explore properties, categories, and atomic weights
            </Text>
          </Stack>
          <Box paddingY="var(--ggui-spacing-2)">
            <SearchField
              value={searchTerm}
              onChange={setSearchTerm}
              placeholder="Search by name or symbol..."
              size="md"
            />
          </Box>
        </Stack>

        <div
          style={{
            display: 'grid',
            gridTemplateColumns: 'repeat(18, 1fr)',
            gap: 'var(--ggui-spacing-1)',
            overflowX: 'auto',
            padding: 'var(--ggui-spacing-2)',
            minWidth: '900px',
          }}
        >
          {elements.map((el) => {
            const colors = getCategoryColors(el.category);
            const active = isHighlighted(el);
            const isSelected = selectedElement?.atomicNumber === el.atomicNumber;

            return (
              <div
                key={el.atomicNumber}
                onClick={() => handleElementClick(el)}
                style={{
                  gridRow: el.row,
                  gridColumn: el.col,
                  aspectRatio: '1/1',
                  cursor: 'pointer',
                  display: 'flex',
                  flexDirection: 'column',
                  padding: 'var(--ggui-spacing-1)',
                  borderRadius: 'var(--ggui-shape-radius-sm)',
                  backgroundColor: colors.bg,
                  border: isSelected ? `2px solid var(--ggui-color-primary-600)` : `1px solid ${colors.border}`,
                  transition: 'all 0.2s ease',
                  opacity: active ? 1 : 0.2,
                  transform: isSelected ? 'scale(1.05)' : 'scale(1)',
                  zIndex: isSelected ? 10 : 1,
                  boxShadow: isSelected ? 'var(--ggui-shape-shadow-md)' : 'none',
                }}
              >
                <Text variant="caption" size="xs" color={colors.text}>
                  {el.atomicNumber}
                </Text>
                <div style={{ flex: 1, display: 'flex', alignItems: 'center', justifyContent: 'center' }}>
                  <Text weight="bold" size="base" color={colors.text}>
                    {el.symbol}
                  </Text>
                </div>
              </div>
            );
          })}
        </div>

        {/* Legend */}
        <Card padding="var(--ggui-spacing-4)" radius="md" border shadow="none">
          <Stack gap="var(--ggui-spacing-2)">
            <Text variant="label">Element Categories</Text>
            <Stack direction="horizontal" gap="var(--ggui-spacing-4)" wrap>
              {categories.map((cat) => {
                const colors = getCategoryColors(cat);
                return (
                  <Stack key={cat} direction="horizontal" align="center" gap="var(--ggui-spacing-2)">
                    <div
                      style={{
                        width: '16px',
                        height: '16px',
                        backgroundColor: colors.bg,
                        border: `1px solid ${colors.border}`,
                        borderRadius: 'var(--ggui-shape-radius-sm)',
                      }}
                    />
                    <Text variant="caption">{cat}</Text>
                  </Stack>
                );
              })}
            </Stack>
          </Stack>
        </Card>

        {selectedElement && (
          <div
            style={{
              backgroundColor: 'var(--ggui-color-surface)',
              padding: 'var(--ggui-spacing-6)',
              borderRadius: 'var(--ggui-shape-radius-lg)',
              boxShadow: 'var(--ggui-shape-shadow-lg)',
              border: '1px solid var(--ggui-color-outlineVariant)',
              animation: 'ggui-slideInUp 300ms ease-out',
              borderLeft: `8px solid ${getCategoryColors(selectedElement.category).border}`,
            }}
          >
            <Stack direction="horizontal" gap="var(--ggui-spacing-8)" align="start" wrap>
              <Box
                style={{
                  width: '120px',
                  height: '120px',
                  display: 'flex',
                  flexDirection: 'column',
                  alignItems: 'center',
                  justifyContent: 'center',
                  backgroundColor: getCategoryColors(selectedElement.category).bg,
                  border: `2px solid ${getCategoryColors(selectedElement.category).border}`,
                  borderRadius: 'var(--ggui-shape-radius-lg)',
                }}
              >
                <Text variant="bodySmall" color={getCategoryColors(selectedElement.category).text}>
                  {selectedElement.atomicNumber}
                </Text>
                <Text
                  size="4xl"
                  weight="bold"
                  color={getCategoryColors(selectedElement.category).text}
                >
                  {selectedElement.symbol}
                </Text>
                <Text variant="caption" color={getCategoryColors(selectedElement.category).text}>
                  {selectedElement.atomicWeight}
                </Text>
              </Box>

              <Stack gap="var(--ggui-spacing-4)" style={{ flex: 1 }}>
                <Stack gap="var(--ggui-spacing-1)">
                  <Heading level={2}>{selectedElement.name}</Heading>
                  <Tag variant="primary">{selectedElement.category}</Tag>
                </Stack>

                <Divider margin="var(--ggui-spacing-1)" />

                <div
                  style={{
                    display: 'grid',
                    gridTemplateColumns: 'repeat(auto-fit, minmax(150px, 1fr))',
                    gap: 'var(--ggui-spacing-4)',
                  }}
                >
                  <Stack gap="0">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                      Atomic Number
                    </Text>
                    <Text weight="semibold">{selectedElement.atomicNumber}</Text>
                  </Stack>
                  <Stack gap="0">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                      Atomic Weight
                    </Text>
                    <Text weight="semibold">{selectedElement.atomicWeight} u</Text>
                  </Stack>
                  <Stack gap="0">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                      Symbol
                    </Text>
                    <Text weight="semibold">{selectedElement.symbol}</Text>
                  </Stack>
                  <Stack gap="0">
                    <Text variant="caption" color="var(--ggui-color-onSurfaceVariant)">
                      Grid Position
                    </Text>
                    <Text weight="semibold">
                      Row {selectedElement.row}, Column {selectedElement.col}
                    </Text>
                  </Stack>
                </div>
              </Stack>
            </Stack>
          </div>
        )}

        {!selectedElement && (
          <div
            style={{
              padding: 'var(--ggui-spacing-12)',
              textAlign: 'center',
              border: '2px dashed var(--ggui-color-outlineVariant)',
              borderRadius: 'var(--ggui-shape-radius-lg)',
            }}
          >
            <Text variant="body" color="var(--ggui-color-onSurfaceVariant)">
              Select an element to view detailed chemical properties.
            </Text>
          </div>
        )}
      </Stack>
    </Container>
  );
}
